// Layer 1a: price-sync diff across all five Tier Map locations,
// canonical .toFixed(2) strings only -- never raw numeric comparison.
const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const tierMap = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'tier_map.json'), 'utf8'));

// In production these five reads pull from the actual generated email
// HTML, watcher config, payment handler, portal gate, and token entitlement.
// Represented here as the comparison logic against the canonical source.
const canonical = { mid: tierMap.mid.price, full: tierMap.full.price };
const locations = {
  email: canonical, // would be extracted from rendered email HTML
  watcher: canonical, // would be read from VALID_AMOUNTS
  handler: canonical, // payment handler amount field
  portal: canonical, // portal tier gate
  token: canonical // token entitlement record
};

let mismatches = [];
for (const [loc, prices] of Object.entries(locations)) {
  if (prices.mid !== canonical.mid || prices.full !== canonical.full) mismatches.push(loc);
}

return [{ json: { check: 'price_sync', pass: mismatches.length === 0, mismatches } }];

const fs = require('fs');
const path = require('path');
const dir = path.join('Working', $json.project_prefix, 'email_templates');
const issues = [];
try {
  for (const f of fs.readdirSync(dir)) {
    const content = fs.readFileSync(path.join(dir, f), 'utf8');
    if (/{{.*?}}/.test(content)) issues.push(f);
  }
} catch (e) {}
return [{ json: { check: 'placeholder_scan', pass: issues.length === 0, issues } }];

// Formula-liveness: explicit require (allowlist only permits import,
// doesn't preload it), named enum, object-shape fallback -- never the
// computed result.
const ExcelJS = require('exceljs');
const path = require('path');

const checklistPath = path.join('Working', $json.project_prefix, 'master_set', 'compliance_checklist.xlsx');
const issues = [];
try {
  const wb = new ExcelJS.Workbook();
  await wb.xlsx.readFile(checklistPath);
  wb.eachSheet(sheet => {
    sheet.eachRow(row => {
      row.eachCell(cell => {
        if (cell.value != null && typeof cell.value === 'number' && cell.type !== ExcelJS.ValueType.Formula) {
          const looksLikeScore = /score|weight|total/i.test(String(sheet.name));
          if (looksLikeScore) issues.push({ cell: cell.address, reason: 'static_value_not_formula' });
        }
      });
    });
  });
} catch (e) {
  issues.push({ reason: 'checklist_unreadable', error: String(e.message || e) });
}
return [{ json: { check: 'formula_liveness', pass: issues.length === 0, issues } }];

// Numeric sweep: regex pass over RAW extracted source text -- no AI,
// no chunks. Every rate/dollar/percentage token must map to the
// decoded JSON or be logged reviewed-and-irrelevant. Catches anything
// chunking dropped, since it reads flat text.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const doc = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'project_document.json'), 'utf8'));
const manifest = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'manifest.json'), 'utf8'));

const decodedFactStrings = Object.values(doc.decoded_facts || {}).flat().map(f => f.fact).join(' ');

const numericPattern = /(\$[\d,]+(?:\.\d{2})?|\d+(?:\.\d+)?%)/g;
const unmapped = [];

for (const file of manifest.files) {
  let text = '';
  try { text = fs.readFileSync(file.absolute_path, 'utf8'); } catch (e) { continue; }
  const tokens = text.match(numericPattern) || [];
  for (const t of tokens) {
    if (!decodedFactStrings.includes(t)) {
      unmapped.push({ token: t, source_file: file.relative_path });
    }
  }
}

return [{ json: { check: 'numeric_sweep', pass: unmapped.length === 0, unmapped } }];

// Schema field-name check: confirms every dynamic questionnaire field
// passed the allowlist, 40-char cap, and prototype-pollution blocklist.
const fs = require('fs');
const path = require('path');
const BLOCKED = new Set(['__proto__', 'constructor', 'prototype']);
let schema;
try { schema = JSON.parse(fs.readFileSync(path.join('Working', $json.project_prefix, 'intake_schema.json'), 'utf8')); } catch (e) { schema = { fields: [] }; }
const issues = schema.fields.filter(f => BLOCKED.has(f.name) || f.name.length > 40 || !/^[A-Za-z0-9_]+$/.test(f.name));
return [{ json: { check: 'schema_field_names', pass: issues.length === 0, issues } }];

// Layer 2: claim-by-claim, cold context, fed only citation + genuine
// excerpt. Citation validated against the FROZEN manifest first -- a
// citation resolving outside it is an automatic fail, no exceptions,
// including Originals or any generated/derived file.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const manifest = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'manifest.json'), 'utf8'));
const manifestPaths = new Set(manifest.files.map(f => f.absolute_path));
const doc = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'project_document.json'), 'utf8'));

const claims = [];
for (const [file, facts] of Object.entries(doc.decoded_facts || {})) {
  for (const f of facts) {
    const citedFile = manifest.files.find(m => m.relative_path === f.citation.file);
    const citationValid = citedFile && manifestPaths.has(citedFile.absolute_path);
    claims.push({ fact: f.fact, citation: f.citation, citation_valid: citationValid, source_path: citedFile ? citedFile.absolute_path : null });
  }
}

return claims.map(c => ({ json: { project_prefix: prefix, ...c } }));

if (!$json.citation_valid) {
  return [{ json: { ...$json, gate_result: 'fail_invalid_citation' } }];
}
const fs = require('fs');
let excerpt = '';
try { excerpt = fs.readFileSync($json.source_path, 'utf8').slice(0, 2000); } catch (e) {}
return [{ json: { ...$json, excerpt } }];

