// Routing: fail -> auto-loop to builder, retry cap 3 per component.
// Cap hit -> human exception. Human check is against the two immutables
// directly -- never Layer 2's self-report.

const fs = require('fs');
const path = require('path');

const results = $input.all().map(i => i.json);
const failures = results.filter(r => r.pass === false || r.gate_result === 'fail_invalid_citation' || r.gate_result === 'fail_unsupported_claim');

const prefix = $('L1: Price-Sync Diff').first().json.project_prefix || results[0]?.project_prefix;
const retryCountPath = path.join('Working', prefix, 'quality_gate_retries.json');
let retries = 0;
try { retries = JSON.parse(fs.readFileSync(retryCountPath, 'utf8')).count || 0; } catch (e) {}

if (failures.length === 0) {
  return [{ json: { project_prefix: prefix, gate_passed: true } }];
}

retries += 1;
fs.writeFileSync(retryCountPath, JSON.stringify({ count: retries }, null, 2), 'utf8');

if (retries >= 3) {
  return [{ json: { project_prefix: prefix, gate_passed: false, human_exception: true, failures } }];
}

return [{ json: { project_prefix: prefix, gate_passed: false, human_exception: false, retry: true, failures } }];
